class Solution {
public:
    int findMinArrowShots(vector<vector<int>>& points) {
        sort(points.begin(), points.end(), cmp);
        int xs = INT_MIN;
        int xe = INT_MIN;
        int shots = 0;
        for(auto i : points){
            if(xe < i[0]){
                shots++;
                xs = i[0];
                xe = i[1];
            }
            else {
                xs = max(xs, i[0]);
                xe = min(xe, i[1]);
            }
        }
        return shots;
    }
private:
    static bool cmp(vector<int>& a, vector<int>& b){
        return a[0] < b[0];
    }
};

class Solution {
public:
    int findMinArrowShots(vector<vector<int>>& points) {
        sort(points.begin(), points.end(), cmp);
        int xs = points[0][1];
        int shots = 1;
        for(auto i : points){
            if(i[0] > xs){
                shots++;
                xs = i[1];
            }
        }
        return shots;
    }
private:
    static bool cmp(vector<int>& a, vector<int>& b){
        return a[1] < b[1];
    }

};
